import { jest } from '@jest/globals';
import ApprovalManager from '../src/agent/ApprovalManager.js';

// Mock dependencies
const mockTerminalInterface = {
  displaySuccess: jest.fn(),
  displayWarning: jest.fn(),
  displayError: jest.fn(),
  displayInfo: jest.fn()
};

const mockConfig = {
  agent: {
    autonomyMode: 'safe',
    autoApproveTools: ['read_file'],
    dangerousCommands: ['rm -rf', 'sudo', 'chmod', 'chown'],
    maxToolCalls: 20
  }
};

describe('ApprovalManager', () => {
  let approvalManager;

  beforeEach(() => {
    jest.clearAllMocks();
    // Reset config to ensure consistent state
    mockConfig.agent.autonomyMode = 'safe';
    mockConfig.agent.autoApproveTools = ['read_file'];
    approvalManager = new ApprovalManager(mockConfig, mockTerminalInterface);
  });

  describe('constructor', () => {
    it('should initialize with config and terminal interface', () => {
      expect(approvalManager.config).toBe(mockConfig);
      expect(approvalManager.terminal).toBe(mockTerminalInterface);
      expect(approvalManager.autonomyMode).toBe('safe');
    });

    it('should throw error if config is missing', () => {
      expect(() => new ApprovalManager(null, mockTerminalInterface))
        .toThrow('Configuration is required');
    });

    it('should throw error if terminal interface is missing', () => {
      expect(() => new ApprovalManager(mockConfig, null))
        .toThrow('TerminalInterface is required');
    });

    it('should set default autonomy mode if not provided', () => {
      const configWithoutMode = { agent: {} };
      const manager = new ApprovalManager(configWithoutMode, mockTerminalInterface);
      expect(manager.autonomyMode).toBe('safe');
    });
  });

  describe('isAutoApproved', () => {
    it('should auto-approve tools in autoApproveTools list', () => {
      const result = approvalManager.isAutoApproved('read_file');
      expect(result).toBe(true);
    });

    it('should not auto-approve dangerous operations', () => {
      const result = approvalManager.isAutoApproved('execute_command', {
        command: 'rm -rf /'
      });
      expect(result).toBe(false);
    });

    it('should follow autonomy mode rules for safe mode', () => {
      approvalManager.setAutonomyMode('safe');
      
      expect(approvalManager.isAutoApproved('read_file')).toBe(true);
      expect(approvalManager.isAutoApproved('list_directory')).toBe(true);
      expect(approvalManager.isAutoApproved('search_code')).toBe(true);
      expect(approvalManager.isAutoApproved('write_file')).toBe(false);
      expect(approvalManager.isAutoApproved('execute_command')).toBe(false);
    });

    it('should follow autonomy mode rules for autonomous mode', () => {
      const autonomousManager = new ApprovalManager(mockConfig, mockTerminalInterface);
      autonomousManager.setAutonomyMode('autonomous');
      
      expect(autonomousManager.isAutoApproved('read_file')).toBe(true);
      expect(autonomousManager.isAutoApproved('write_file')).toBe(true);
      expect(autonomousManager.isAutoApproved('execute_command')).toBe(false);
    });

    it('should follow autonomy mode rules for full mode', () => {
      const fullManager = new ApprovalManager(mockConfig, mockTerminalInterface);
      fullManager.setAutonomyMode('full');
      
      expect(fullManager.isAutoApproved('read_file')).toBe(true);
      expect(fullManager.isAutoApproved('write_file')).toBe(true);
      expect(fullManager.isAutoApproved('execute_command')).toBe(true);
    });
  });

  describe('isDangerous', () => {
    it('should identify dangerous execute_command operations', () => {
      const testCases = [
        { command: 'rm -rf /', expected: true },
        { command: 'sudo apt-get install', expected: true },
        { command: 'chmod 777 file.txt', expected: true },
        { command: 'ls -la', expected: false },
        { command: 'cat file.txt', expected: false },
        { command: 'echo hello', expected: false }
      ];

      testCases.forEach(({ command, expected }) => {
        const result = approvalManager.isDangerous('execute_command', { command });
        expect(result).toBe(expected);
      });
    });

    it('should identify dangerous file operations', () => {
      const testCases = [
        { path: '/etc/passwd', expected: true },
        { path: 'package.json', expected: true },
        { path: '.env', expected: true },
        { path: 'src/myfile.js', expected: false },
        { path: 'README.md', expected: false }
      ];

      testCases.forEach(({ path, expected }) => {
        const result = approvalManager.isDangerous('write_file', { path });
        expect(result).toBe(expected);
      });
    });

    it('should identify dangerous batch file operations', () => {
      const manyFiles = Array(60).fill().map((_, i) => ({ path: `file${i}.js`, content: 'test' }));
      const fewFiles = Array(5).fill().map((_, i) => ({ path: `file${i}.js`, content: 'test' }));

      expect(approvalManager.isDangerous('create_multiple_files', { files: manyFiles })).toBe(true);
      expect(approvalManager.isDangerous('create_multiple_files', { files: fewFiles })).toBe(false);
    });

    it('should return false for non-dangerous operations', () => {
      expect(approvalManager.isDangerous('read_file', { path: 'test.js' })).toBe(false);
      expect(approvalManager.isDangerous('list_directory', { path: '.' })).toBe(false);
      expect(approvalManager.isDangerous('search_code', { query: 'function' })).toBe(false);
    });
  });

  describe('requestApproval', () => {
    it('should auto-approve safe operations', async () => {
      const result = await approvalManager.requestApproval('read_file', { path: 'test.js' });
      expect(result).toBe(true);
    });

    it('should record auto-approval in history', async () => {
      await approvalManager.requestApproval('read_file', { path: 'test.js' });
      
      const history = approvalManager.getApprovalHistory();
      expect(history).toHaveLength(1);
      expect(history[0]).toMatchObject({
        toolName: 'read_file',
        approved: true,
        reason: 'auto-approved'
      });
    });
  });

  describe('setAutonomyMode', () => {
    it('should set valid autonomy modes', () => {
      const validModes = ['safe', 'autonomous', 'full'];
      
      validModes.forEach(mode => {
        expect(() => approvalManager.setAutonomyMode(mode)).not.toThrow();
        expect(approvalManager.getAutonomyMode()).toBe(mode);
      });
    });

    it('should throw error for invalid autonomy mode', () => {
      expect(() => approvalManager.setAutonomyMode('invalid'))
        .toThrow('Invalid autonomy mode: invalid');
    });

    it('should update configuration', () => {
      approvalManager.setAutonomyMode('autonomous');
      expect(mockConfig.agent.autonomyMode).toBe('autonomous');
    });

    it('should display success message', () => {
      approvalManager.setAutonomyMode('autonomous');
      expect(mockTerminalInterface.displaySuccess).toHaveBeenCalledWith(
        expect.stringContaining('Autonomy mode changed')
      );
    });
  });

  describe('getAutonomyMode', () => {
    it('should return current autonomy mode', () => {
      expect(approvalManager.getAutonomyMode()).toBe('safe');
      
      approvalManager.setAutonomyMode('autonomous');
      expect(approvalManager.getAutonomyMode()).toBe('autonomous');
    });
  });

  describe('addAutoApprovalTool', () => {
    it('should add tool to auto-approve list', () => {
      approvalManager.addAutoApprovalTool('new_tool');
      
      expect(approvalManager.isAutoApproved('new_tool')).toBe(true);
      expect(mockConfig.agent.autoApproveTools).toContain('new_tool');
    });

    it('should throw error for invalid tool name', () => {
      expect(() => approvalManager.addAutoApprovalTool(''))
        .toThrow('Tool name must be a non-empty string');
      
      expect(() => approvalManager.addAutoApprovalTool(null))
        .toThrow('Tool name must be a non-empty string');
    });
  });

  describe('removeAutoApprovalTool', () => {
    it('should remove tool from auto-approve list', () => {
      approvalManager.addAutoApprovalTool('test_tool');
      expect(approvalManager.isAutoApproved('test_tool')).toBe(true);
      
      approvalManager.removeAutoApprovalTool('test_tool');
      expect(approvalManager.isAutoApproved('test_tool')).toBe(false);
    });

    it('should handle removing non-existent tool', () => {
      approvalManager.removeAutoApprovalTool('non_existent');
      expect(mockTerminalInterface.displayWarning).toHaveBeenCalledWith(
        'Tool "non_existent" was not in auto-approve list'
      );
    });
  });

  describe('getApprovalHistory', () => {
    it('should return approval history', async () => {
      await approvalManager.requestApproval('read_file', { path: 'test1.js' });
      await approvalManager.requestApproval('read_file', { path: 'test2.js' });
      
      const history = approvalManager.getApprovalHistory();
      expect(history).toHaveLength(2);
    });

    it('should limit history entries', async () => {
      await approvalManager.requestApproval('read_file', { path: 'test1.js' });
      await approvalManager.requestApproval('read_file', { path: 'test2.js' });
      
      const history = approvalManager.getApprovalHistory(1);
      expect(history).toHaveLength(1);
    });
  });

  describe('clearApprovalHistory', () => {
    it('should clear approval history', async () => {
      await approvalManager.requestApproval('read_file', { path: 'test.js' });
      expect(approvalManager.getApprovalHistory()).toHaveLength(1);
      
      approvalManager.clearApprovalHistory();
      expect(approvalManager.getApprovalHistory()).toHaveLength(0);
    });
  });

  describe('handleModeCommand', () => {
    it('should change autonomy mode when valid mode provided', () => {
      const result = approvalManager.handleModeCommand('autonomous');
      expect(result).toBe(true);
      expect(approvalManager.getAutonomyMode()).toBe('autonomous');
    });

    it('should display current mode info when no mode provided', () => {
      const result = approvalManager.handleModeCommand();
      expect(result).toBe(true);
    });

    it('should handle invalid mode gracefully', () => {
      const result = approvalManager.handleModeCommand('invalid');
      expect(result).toBe(false);
      expect(mockTerminalInterface.displayError).toHaveBeenCalledWith(
        expect.stringContaining('Failed to set autonomy mode')
      );
    });
  });

  describe('getApprovalStats', () => {
    it('should return approval statistics', async () => {
      await approvalManager.requestApproval('read_file', { path: 'test1.js' }); // auto-approved
      await approvalManager.requestApproval('list_directory', { path: '.' }); // auto-approved
      await approvalManager.requestApproval('search_code', { query: 'test' }); // auto-approved
      
      const stats = approvalManager.getApprovalStats();
      
      expect(stats.total).toBe(3);
      expect(stats.autoApproved).toBe(3);
      expect(stats.toolStats.read_file.total).toBe(1);
      expect(stats.toolStats.list_directory.total).toBe(1);
      expect(stats.toolStats.search_code.total).toBe(1);
    });
  });
});